// GST API Integration Module
// Real API targets: https://api.gst.gov.in/taxpayerapi/v1.0/
// Authentication is 2-step: initiate (triggers OTP) → verify OTP → get session token
// Requires GSP (GST Suvidha Provider) App Key set via GST_APP_KEY env variable

interface GSTCredentials {
  gstin: string
  username: string
  apiKey: string
}

export interface GSTAuthResponse {
  success: boolean
  token?: string
  error?: string
}

export interface GSTInitAuthResponse {
  success: boolean
  refId?: string
  error?: string
}

export interface GSTVerifyOTPResponse {
  success: boolean
  token?: string
  error?: string
}

interface GSTLedgerEntry {
  date: string
  description: string
  debitAmount: number
  creditAmount: number
  balance: number
  transactionId: string
  period: string
}

export class GSTAPIClient {
  private baseURL: string
  private credentials: GSTCredentials | null = null
  private authToken: string | null = null
  private useMockAPI: boolean

  constructor(useMockAPI = true) {
    this.useMockAPI = useMockAPI
    this.baseURL = process.env.GST_API_BASE_URL || "https://api.gst.gov.in/taxpayerapi/v1.0"
  }

  setCredentials(credentials: GSTCredentials) {
    this.credentials = credentials
  }

  // ─── Step 1: Initiate authentication — GST portal sends OTP to user's mobile ──
  async initiateAuth(gstin: string, username: string): Promise<GSTInitAuthResponse> {
    if (this.useMockAPI) {
      // Mock: skip OTP, return a fake refId immediately
      return { success: true, refId: `mock-ref-${Date.now()}` }
    }

    const appKey = process.env.GST_APP_KEY
    const clientId = process.env.GST_CLIENT_ID

    if (!appKey || !clientId) {
      return {
        success: false,
        error: "GST_APP_KEY and GST_CLIENT_ID environment variables are required for real GST API access. These are issued by GSTN to registered GST Suvidha Providers (GSPs).",
      }
    }

    try {
      const response = await fetch(`${this.baseURL}/authenticate`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          clientid: clientId,
          "client-secret": appKey,
          action: "AUTHTOKEN",
        },
        body: JSON.stringify({
          action: "AUTHTOKEN",
          username,
          gstin,
        }),
      })

      const data = await response.json()

      if (!response.ok || data.error) {
        return { success: false, error: data.error?.message || "OTP request failed" }
      }

      return { success: true, refId: data.data?.ref_id || data.ref_id }
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : "Failed to connect to GST portal",
      }
    }
  }

  // ─── Step 2: Verify OTP — returns session token ───────────────────────────────
  async verifyOTP(refId: string, otp: string): Promise<GSTVerifyOTPResponse> {
    if (this.useMockAPI || refId.startsWith("mock-ref-")) {
      // Mock: any 6-digit OTP passes
      if (otp.length === 6) {
        const token = `mock-session-${Date.now()}`
        this.authToken = token
        return { success: true, token }
      }
      return { success: false, error: "OTP must be 6 digits" }
    }

    const appKey = process.env.GST_APP_KEY
    const clientId = process.env.GST_CLIENT_ID

    if (!appKey || !clientId) {
      return { success: false, error: "GST_APP_KEY and GST_CLIENT_ID are not configured" }
    }

    try {
      const response = await fetch(`${this.baseURL}/authenticate`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          clientid: clientId,
          "client-secret": appKey,
          action: "OTPTOKEN",
        },
        body: JSON.stringify({
          action: "OTPTOKEN",
          username: this.credentials?.username,
          app_key: appKey,
          rek: refId,
          otp,
        }),
      })

      const data = await response.json()

      if (!response.ok || data.error) {
        return { success: false, error: data.error?.message || "OTP verification failed" }
      }

      const token = data.data?.auth_token || data.auth_token
      this.authToken = token
      return { success: true, token }
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : "OTP verification failed",
      }
    }
  }

  // ─── Authenticate with stored session token (for sync operations) ─────────────
  async authenticate(): Promise<GSTAuthResponse> {
    if (!this.credentials) {
      return { success: false, error: "Credentials not set" }
    }

    try {
      if (this.useMockAPI) {
        const response = await fetch("/api/gst/mock", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ action: "authenticate" }),
        })
        const data = await response.json()
        if (data.success && data.token) {
          this.authToken = data.token
        }
        return data
      }

      // Real mode: use stored API key as session token (set after OTP verification)
      if (this.credentials.apiKey) {
        this.authToken = this.credentials.apiKey
        return { success: true, token: this.credentials.apiKey }
      }

      return {
        success: false,
        error: "No session token found. Please reconnect via Settings → GST.",
      }
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : "Authentication failed",
      }
    }
  }

  // ─── Fetch electronic cash ledger ─────────────────────────────────────────────
  async fetchCashLedger(fromDate: string, toDate: string): Promise<GSTLedgerEntry[]> {
    if (!this.authToken) {
      throw new Error("Not authenticated. Call authenticate() first.")
    }

    if (this.useMockAPI) {
      const response = await fetch("/api/gst/mock", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "cash_ledger", fromDate, toDate }),
      })
      const data = await response.json()
      return data.data
    }

    const clientId = process.env.GST_CLIENT_ID || ""
    const response = await fetch(
      `${this.baseURL}/ledger/cash?gstin=${this.credentials?.gstin}&fromDate=${fromDate}&toDate=${toDate}`,
      {
        headers: {
          "Content-Type": "application/json",
          clientid: clientId,
          "auth-token": this.authToken,
        },
      }
    )

    if (!response.ok) {
      const err = await response.json().catch(() => ({}))
      throw new Error(err?.error?.message || `Ledger fetch failed (${response.status})`)
    }

    const data = await response.json()
    // Normalize GST portal response format to our internal format
    return (data.data?.ledger || []).map((e: any) => ({
      date: e.dt,
      description: e.desc,
      debitAmount: Number(e.damt || 0),
      creditAmount: Number(e.camt || 0),
      balance: Number(e.bal || 0),
      transactionId: e.txid,
      period: e.rp,
    }))
  }

  // ─── Fetch GSTR-1 (outward supplies) ──────────────────────────────────────────
  async fetchGSTR1(period: string): Promise<any> {
    if (!this.authToken) {
      throw new Error("Not authenticated. Call authenticate() first.")
    }

    if (this.useMockAPI) {
      const response = await fetch("/api/gst/mock", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "gstr1", period }),
      })
      const data = await response.json()
      return data.data
    }

    const clientId = process.env.GST_CLIENT_ID || ""
    const response = await fetch(
      `${this.baseURL}/returns/gstr1?gstin=${this.credentials?.gstin}&ret_period=${period}`,
      {
        headers: {
          "Content-Type": "application/json",
          clientid: clientId,
          "auth-token": this.authToken,
        },
      }
    )

    if (!response.ok) {
      const err = await response.json().catch(() => ({}))
      throw new Error(err?.error?.message || `GSTR-1 fetch failed (${response.status})`)
    }

    const data = await response.json()
    return data.data
  }

  // ─── Fetch GSTR-3B summary ────────────────────────────────────────────────────
  async fetchGSTR3B(period: string): Promise<any> {
    if (!this.authToken) {
      throw new Error("Not authenticated. Call authenticate() first.")
    }

    if (this.useMockAPI) {
      const response = await fetch("/api/gst/mock", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "gstr3b", period }),
      })
      const data = await response.json()
      return data.data
    }

    const clientId = process.env.GST_CLIENT_ID || ""
    const response = await fetch(
      `${this.baseURL}/returns/gstr3b?gstin=${this.credentials?.gstin}&ret_period=${period}`,
      {
        headers: {
          "Content-Type": "application/json",
          clientid: clientId,
          "auth-token": this.authToken,
        },
      }
    )

    if (!response.ok) {
      const err = await response.json().catch(() => ({}))
      throw new Error(err?.error?.message || `GSTR-3B fetch failed (${response.status})`)
    }

    const data = await response.json()
    return data.data
  }
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

// Validates the 15-character GSTIN format
// Structure: 2-digit state code + 10-char PAN + entity number + alphabet + checksum
export function validateGSTIN(gstin: string): boolean {
  const gstinRegex = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/
  return gstinRegex.test(gstin)
}

// Formats a JS Date into the MMYYYY period string the GST portal uses
export function formatGSTPeriod(date: Date): string {
  const month = String(date.getMonth() + 1).padStart(2, "0")
  const year = date.getFullYear()
  return `${month}${year}`
}

"use client"

import type React from "react"
import { useState, useEffect } from "react"
import { fetchFromAPI } from "@/lib/fetch"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { Switch } from "@/components/ui/switch"
import {
  CheckCircle2, XCircle, Loader2, RefreshCw, TestTube,
  Smartphone, ShieldCheck, AlertCircle, ExternalLink, Info,
} from "lucide-react"

type ConnectStep = "credentials" | "otp" | "done"

export function GSTCredentialsForm() {
  const [isLoading, setIsLoading] = useState(false)
  const [isTesting, setIsTesting] = useState(false)
  const [isSyncing, setIsSyncing] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [success, setSuccess] = useState<string | null>(null)
  const [integrated, setIntegrated] = useState(false)
  const [lastSync, setLastSync] = useState<string | null>(null)
  const [useMockAPI, setUseMockAPI] = useState(true)

  // 2-step connect state (real mode only)
  const [connectStep, setConnectStep] = useState<ConnectStep>("credentials")
  const [refId, setRefId] = useState<string | null>(null)
  const [otp, setOtp] = useState("")

  const [formData, setFormData] = useState({ gstin: "", username: "" })

  useEffect(() => {
    loadCredentials()
  }, [])

  const loadCredentials = async () => {
    try {
      const data = await fetchFromAPI("/api/gst/credentials")
      setFormData({ gstin: data.gstin || "", username: data.username || "" })
      setIntegrated(data.integrated)
      setLastSync(data.lastSync)
    } catch {
      // Profile may not exist yet — ignore
    }
  }

  // ── Step 1: Submit GSTIN + username (or mock connect) ────────────────────────
  const handleStep1 = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    setError(null)
    setSuccess(null)

    try {
      const result = await fetchFromAPI("/api/gst/credentials", {
        method: "POST",
        body: JSON.stringify({ ...formData, useMockAPI }),
      })

      if (useMockAPI) {
        // Mock mode: done in one step
        setIntegrated(true)
        setConnectStep("done")
        setSuccess("Mock GST connected successfully. Your GST data is ready to sync.")
      } else if (result.otpRequired) {
        // Real mode: move to OTP entry step
        setRefId(result.refId)
        setConnectStep("otp")
        setSuccess("OTP sent to your GST-registered mobile number.")
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to connect")
    } finally {
      setIsLoading(false)
    }
  }

  // ── Step 2: Verify OTP (real mode only) ─────────────────────────────────────
  const handleOTPVerify = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    setError(null)
    setSuccess(null)

    try {
      await fetchFromAPI("/api/gst/credentials", {
        method: "PATCH",
        body: JSON.stringify({ refId, otp }),
      })
      setIntegrated(true)
      setConnectStep("done")
      setSuccess("GST portal connected successfully!")
    } catch (err) {
      setError(err instanceof Error ? err.message : "OTP verification failed")
    } finally {
      setIsLoading(false)
    }
  }

  const testConnection = async () => {
    setIsTesting(true)
    setError(null)
    setSuccess(null)
    try {
      const result = await fetchFromAPI("/api/gst/credentials", { method: "PUT" })
      if (result.success) {
        setSuccess("Connection test passed!")
        setTimeout(() => setSuccess(null), 3000)
      } else {
        setError(result.message || "Connection test failed")
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Connection test failed")
    } finally {
      setIsTesting(false)
    }
  }

  const syncNow = async () => {
    setIsSyncing(true)
    setError(null)
    setSuccess(null)
    try {
      const today = new Date()
      const thirtyDaysAgo = new Date(today)
      thirtyDaysAgo.setDate(today.getDate() - 30)

      await fetchFromAPI("/api/gst/sync", {
        method: "POST",
        body: JSON.stringify({
          syncType: "cash_ledger",
          fromDate: thirtyDaysAgo.toISOString().split("T")[0],
          toDate: today.toISOString().split("T")[0],
          useMockAPI,
        }),
      })

      setSuccess("Sync complete!")
      setLastSync(new Date().toISOString())
      setTimeout(() => setSuccess(null), 3000)
    } catch (err) {
      setError(err instanceof Error ? err.message : "Sync failed")
    } finally {
      setIsSyncing(false)
    }
  }

  const handleDisconnect = () => {
    setIntegrated(false)
    setConnectStep("credentials")
    setRefId(null)
    setOtp("")
    setSuccess(null)
    setError(null)
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <div>
            <CardTitle>GST Integration</CardTitle>
            <CardDescription>Connect to the GST portal to sync your tax data</CardDescription>
          </div>
          {integrated ? (
            <Badge variant="default" className="gap-1">
              <CheckCircle2 className="h-3 w-3" />
              Connected
            </Badge>
          ) : (
            <Badge variant="secondary" className="gap-1">
              <XCircle className="h-3 w-3" />
              Not Connected
            </Badge>
          )}
        </div>
      </CardHeader>

      <CardContent className="space-y-5">
        {/* Mock mode toggle */}
        <div className="flex items-center justify-between rounded-lg border p-4 bg-muted/30">
          <div className="flex items-center gap-3">
            <TestTube className="h-5 w-5 text-muted-foreground" />
            <div>
              <Label htmlFor="mock-mode" className="text-base cursor-pointer">
                Use Mock Data (Testing Mode)
              </Label>
              <p className="text-xs text-muted-foreground mt-0.5">
                Test all GST features without real credentials
              </p>
            </div>
          </div>
          <Switch
            id="mock-mode"
            checked={useMockAPI}
            onCheckedChange={(v) => {
              setUseMockAPI(v)
              setConnectStep("credentials")
              setError(null)
              setSuccess(null)
            }}
          />
        </div>

        {/* ── Real mode: GSP requirement notice ── */}
        {!useMockAPI && (
          <div className="rounded-lg border border-amber-200 bg-amber-50 dark:border-amber-900 dark:bg-amber-950 p-4 space-y-2">
            <div className="flex items-center gap-2">
              <AlertCircle className="h-4 w-4 text-amber-600 dark:text-amber-400 shrink-0" />
              <p className="text-sm font-semibold text-amber-800 dark:text-amber-200">
                GSP Registration Required for Live Connection
              </p>
            </div>
            <p className="text-xs text-amber-700 dark:text-amber-300 leading-relaxed">
              Direct GST API access requires a <strong>GST_APP_KEY</strong> and <strong>GST_CLIENT_ID</strong> issued by
              GSTN to registered GST Suvidha Providers (GSPs). Without this, real-mode requests will fail.
              Use mock mode to try all features now, and configure your GSP keys in <code className="bg-amber-100 dark:bg-amber-900 px-1 rounded">.env.local</code> when ready for production.
            </p>
            <a
              href="https://developer.gst.gov.in/apiportal/taxpayer"
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-1 text-xs text-amber-700 dark:text-amber-300 underline"
            >
